const parents = {
  'internet-banking': 'awareness',
  'mobile-banking':   'awareness',
  'upi':              'awareness',
  'bill-payments':    'awareness',
  'wallets':          'awareness',
  'cashless':         'awareness',
  'phishing':         'fraud',
  'otp-scam':         'fraud',
  'fake-calls':       'fraud',
  'atm-skimming':     'fraud',
  'lottery-scam':     'fraud',
  'passwords':        'prevention',
  'two-factor':       'prevention',
  'safe-browsing':    'prevention',
  'wifi-safety':      'prevention'
};

function go(page) {
  if (!PM[page]) page = 'home';

  // Update active states
  document.querySelectorAll('.sbtn, .ssub').forEach(btn => btn.classList.remove('active'));
  const activeBtn = document.getElementById('b-' + page);
  if (activeBtn) activeBtn.classList.add('active');

  // Highlight parent section button if on a sub-page
  const parentPage = parents[page];
  if (parentPage) {
    const parentBtn = document.getElementById('b-' + parentPage);
    if (parentBtn) parentBtn.classList.add('active');
  }

  // Render content
  document.getElementById('pc').innerHTML = PM[page];

  // Scroll to top
  window.scrollTo({ top: 0, behavior: 'smooth' });

  // Close mobile sidebar
  closeSB();
}

function openSB() {
  document.getElementById('sb').classList.add('open');
  document.getElementById('ov').classList.add('open');
}

function closeSB() {
  document.getElementById('sb').classList.remove('open');
  document.getElementById('ov').classList.remove('open');
}

// Boot on home page
go('home');